import { EDHOC, DefaultEdhocCredentialManager, DefaultEdhocCryptoManager, EdhocMethod, EdhocSuite, X509Credentials } from '../dist/index'

const credentialManagerI = new DefaultEdhocCredentialManager();
const cryptoManagerI = new DefaultEdhocCryptoManager();

const credentialManagerR = new DefaultEdhocCredentialManager();
const cryptoManagerR = new DefaultEdhocCryptoManager();

const certificateI_p256 = new X509Credentials(
    Buffer.from('', 'hex'), 
    Buffer.from('DC1FBB05B6B08360CE5B9EEA08EBFBFC6766A21340641863D4C8A3F68F096337', 'hex')
);

const certificateR_p256 = new X509Credentials(
    Buffer.from('', 'hex'), 
    Buffer.from('EE6287116FE27CDC539629DC87E12BF8EAA2229E7773AA67BC4C0FBA96E7FBB2', 'hex')
);

const rootCertificate_p256 = Buffer.from('', 'hex');

credentialManagerI.addTrustRoot(rootCertificate_p256);
credentialManagerR.addTrustRoot(rootCertificate_p256);

credentialManagerI.setCredentials(cryptoManagerI, certificateI_p256);
credentialManagerR.setCredentials(cryptoManagerR, certificateR_p256);

const method = [EdhocMethod.Method1];
const method_r = [EdhocMethod.Method2, EdhocMethod.Method0, EdhocMethod.Method1];

const initiator = new EDHOC(10, method, [ EdhocSuite.Suite2], credentialManagerI, cryptoManagerI);
const responder = new EDHOC(20, method_r, [ EdhocSuite.Suite1, EdhocSuite.Suite3, EdhocSuite.Suite4 ], credentialManagerR, cryptoManagerR);

// initiator.logger = (name, value) => console.log("INITIATOR", name, value.toString('hex'));
// responder.logger = (name, value) => console.log(colors.red("RESPONDER"), colors.green(name), colors.yellow(value.toString('hex')), "\n");

async function run() {
    try {

        const message_1 = await initiator.composeMessage1([{ label: 100, value: Buffer.from('This is a test message') }]);
        console.log("message_1", message_1);      

        console.log("initiator.cipherSuites", initiator.cipherSuites);
        console.log("responder.cipherSuites", responder.cipherSuites);

        try {
        const ead_1 = await responder.processMessage1(message_1);
        }
        catch {
            //
        }
        console.log("initiator.cipherSuites", initiator.selectedSuite);
        console.log("responder.cipherSuites", responder.selectedSuite);
        
    }
    catch (error) {
        console.log(error);
    }
}
run();
